import{_ as s,o as n,c as p,ag as e}from"./chunks/framework.BZohXCq9.js";const t="/assets/Lisp%E7%9A%84%E6%A0%B9%E6%BA%90.C4YLusmE.jpg",u=JSON.parse('{"title":"【文档翻译】Lisp 的根源 - Lisp 编程语言的起源、进化与魅力","description":"本文介绍了 Lisp 编程语言的起源、核心思想以及其发展历程。原文作者 Paul Graham 向我们展现了Lisp如何通过简单的数据结构（列表）和基本函数来创造一种简洁而强大的编程语言。他还阐述了 Lisp 的宏、闭包和动态作用域等特性。本文将帮助读者深入理解 Lisp 这门编程语言的本质和魅力。","frontmatter":{"title":"【文档翻译】Lisp 的根源 - Lisp 编程语言的起源、进化与魅力","date":"2023-03-13T13:54:28.000Z","description":"本文介绍了 Lisp 编程语言的起源、核心思想以及其发展历程。原文作者 Paul Graham 向我们展现了Lisp如何通过简单的数据结构（列表）和基本函数来创造一种简洁而强大的编程语言。他还阐述了 Lisp 的宏、闭包和动态作用域等特性。本文将帮助读者深入理解 Lisp 这门编程语言的本质和魅力。","tags":["Lisp","Lisp 之根","Lisp 的根源","The Roots of Lisp","文档翻译"],"categories":["文档翻译"]},"headers":[],"relativePath":"posts/【文档翻译】Lisp 的根源/index.md","filePath":"posts/【文档翻译】Lisp 的根源/index.md","lastUpdated":null}'),i={name:"posts/【文档翻译】Lisp 的根源/index.md"};function o(l,a,r,c,d,h){return n(),p("div",null,[...a[0]||(a[0]=[e('<p>《Lisp 的根源》是一个介绍 Lisp 编程语言的起源和核心思想的文章，由 Paul Graham 所著。Lisp 是由 John McCarthy 基于 λ 演算和递归函数的理论，用一种简单的数据结构——列表和几个核心函数创造出来的一门简洁且强大的编程语言。本文不仅展示了如何用 Lisp 实现其编译器和解释器，同时也说明了 Lisp 的一些重要特性如宏、闭包和动态作用域，目的在于让读者深入了解 Lisp 的本质和魅力。</p><p><img src="'+t+`" alt="Lisp 漫画"></p><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>在 1960 年，John McCarthy 发表了一篇杰出的论文，他为编程做了类似于 <a href="#note1">Euclid 为几何所做的事情 <sup>[1]</sup></a>。他展示了如何通过一些简单的运算符和函数符号，构建一个完整的编程语言。他将这种语言称为 Lisp，即列表处理，因为他的一个关键思想是使用一种称为列表的简单数据结构来表示代码和数据。</p><p>了解 McCarthy 发现的内容是值得的，它不仅仅是作为计算机历史上的一个里程碑，而是作为我们现在编程趋势的一个模型。我认为到目前为止，已经有两个非常清晰、一致的编程模型：C 模型和 Lisp 模型。</p><p>这两种似乎是高地，中间是沼泽低地。随着计算机变得更强大，新开发的语言一直在向 Lisp 模型靠拢。过去 20 年中，一种流行的新编程语言的配方是：取 C 模型的计算方式，并逐渐加入从 Lisp 模型中取出的部分，如运行时类型和垃圾回收。</p><p>在这篇文章中，我将尽可能简单地解释麦卡锡发现了什么。目的不仅仅是了解 40 年前某人发现了一个有趣的理论结果，而且是要展示语言正在走向何方。Lisp 与众不同之处——事实上，Lisp 的定义特征——就是它可以用自身来编写。要理解麦卡锡这样说的意思，我们要重走他的步骤，把他的数学符号翻译成可以运行的 Common Lisp 代码。</p><h2 id="七个原始操作符" tabindex="-1">七个原始操作符 <a class="header-anchor" href="#七个原始操作符" aria-label="Permalink to &quot;七个原始操作符&quot;">​</a></h2><p>一开始，我们定义一个表达式。一个表达式要么是一个原子，由一系列英文字母（例如 foo）组成；要么是一个由零个或多个表达式组成的列表，用空格分隔并用括号括起来。这是一些表达式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>foo</span></span>
<span class="line"><span>()</span></span>
<span class="line"><span>(foo)</span></span>
<span class="line"><span>(foo bar)</span></span>
<span class="line"><span>(a b (c) d)</span></span></code></pre></div><p>通过算数，表达式 <strong><em>1 + 1</em></strong> 得到值 <strong><em>2</em></strong>。合法的 Lisp 表达式也会得到值。如果一个表达式 <strong><em>e</em></strong> 产生一个值 <strong><em>v</em></strong> 我们说 <strong><em>e 返回 v</em></strong>。我们下一步定义有什么种类的表达式，以及每种类型返回什么值。</p><p>如果表达式是一个列表，我们称第一个元素为操作符，并且剩下的元素称为参数。我们接下来定义七个原始(某种意义上的公理)操作符：<a href="#quote"><strong>quote</strong></a>，<a href="#atom"><strong>atom</strong></a>，<strong>eq</strong>，<strong>car</strong>，<strong>cdr</strong>，<strong>cons</strong> 和 <strong>cond</strong></p><h3 id="quote" tabindex="-1">quote <a class="header-anchor" href="#quote" aria-label="Permalink to &quot;quote&quot;">​</a></h3><p>(quote x) 返回 x。为了可读性，我们将 (quote x) 记为 &#39;x</p><div class="language-repl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">repl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; (quote a)</span></span>
<span class="line"><span>a</span></span>
<span class="line"><span>&gt; &#39;a</span></span>
<span class="line"><span>a</span></span>
<span class="line"><span>&gt; (quote (a b c))</span></span>
<span class="line"><span>(a b c)</span></span></code></pre></div><h3 id="atom" tabindex="-1">atom <a class="header-anchor" href="#atom" aria-label="Permalink to &quot;atom&quot;">​</a></h3><p>如果 x 是原子或空列表 ，(atom x) 返回元素 t 。其他情况返回 () 。在 Lisp 中我们按照管理使用原子 t 表示真，并且使用空列表表示假。</p><div class="language-repl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">repl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; (atom &#39;a)</span></span>
<span class="line"><span>t</span></span>
<span class="line"><span>&gt; (atom &#39;(a b c))</span></span>
<span class="line"><span>()</span></span>
<span class="line"><span>&gt; (atom &#39;())</span></span>
<span class="line"><span>t</span></span></code></pre></div><p>既然我们现在有了一个参数被求值的操作，我们就可以展示 quote 的用途了。通过引用一个列表，我们可以保护它免于求值。当一个未引用的列表作为操作符（如 atom）的参数时，它会被当作代码来处理。</p><div class="language-repl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">repl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; (atom (atom &#39;a))</span></span>
<span class="line"><span>t</span></span></code></pre></div><p>当一个列表被 quote 时，它会被当作一个普通的列表来处理。在这种情况下，它是一个包含两个元素的列表。</p><div class="language-repl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">repl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; (atom &#39;(atom ）&#39;a))</span></span>
<span class="line"><span>()</span></span></code></pre></div><p>这对应于我们在英语中使用引号的方式。Cambridge 是马萨诸塞州的一个城镇，大约有 90,000 人。&quot;Cambridge&quot; 是一个包含九个字母的单词。</p><p>quote 可能看起来是有点陌生的概念，因为很少有其他语言有类似的东西。它与 Lisp 最独特的特征之一密不可分：代码和数据由相同的数据结构构成，quote 运算符是我们区分它们的方式。</p><h3 id="eq" tabindex="-1">eq <a class="header-anchor" href="#eq" aria-label="Permalink to &quot;eq&quot;">​</a></h3><p>如果 x 和 y 的值是相同的原子或都是空列表，则 (eq x y) 返回 t ，否则返回 () 。</p><p><strong>未完待续...</strong></p><h2 id="注" tabindex="-1">注 <a class="header-anchor" href="#注" aria-label="Permalink to &quot;注&quot;">​</a></h2><div id="note1"></div> [1]《符号表达式的递归函数及其机器计算，第一部分》ACM 通讯 3:4，1960年4月，184-195页 `,30)])])}const m=s(i,[["render",o]]);export{u as __pageData,m as default};
